  1→// lib/serval-server/h1/reader.zig
  2→//! HTTP/1.1 Request Reading Utilities
  3→//!
  4→//! Zero-allocation request reading for HTTP/1.1 connections.
  5→//! Handles partial header accumulation and body length extraction.
  6→//! TigerStyle: Explicit parameters, bounded operations.
  7→
  8→const std = @import("std");
  9→const assert = std.debug.assert;
 10→const Io = std.Io;
 11→
 12→const serval_core = @import("serval-core");
 13→const config = serval_core.config;
 14→const debugLog = serval_core.debugLog;
 15→const types = serval_core.types;
 16→const Request = types.Request;
 17→
 18→const serval_http = @import("serval-http");
 19→const parseContentLengthValue = serval_http.parseContentLengthValue;
 20→
 21→/// Buffer size for reading HTTP requests (from centralized config).
 22→const REQUEST_BUFFER_SIZE_BYTES = config.REQUEST_BUFFER_SIZE_BYTES;
 23→
 24→/// Read request bytes from stream into buffer.
 25→/// Returns byte count or null on error/EOF.
 26→/// TigerStyle: Explicit parameters, no hidden state.
 27→pub fn readRequest(io: Io, stream: Io.net.Stream, recv_buf: *[REQUEST_BUFFER_SIZE_BYTES]u8) ?usize {
 28→    // Precondition: buffer pointer must be valid
 29→    assert(@intFromPtr(recv_buf) != 0);
 30→
 31→    var reader_buf: [1]u8 = std.mem.zeroes([1]u8);
 32→    var reader = stream.reader(io, &reader_buf);
 33→    var bufs: [1][]u8 = .{recv_buf};
 34→    const n = reader.interface.readVec(&bufs) catch |err| {
 35→        if (err != error.EndOfStream) {
 36→            debugLog("Read error: {s}", .{@errorName(err)});
 37→        }
 38→        return null;
 39→    };
 40→
 41→    // Postcondition: return null if no bytes read (client closed)
 42→    if (n == 0) return null;
 43→    return n;
 44→}
 45→
 46→/// Read additional data into remaining buffer space for partial header accumulation.
 47→/// Used when headers span multiple TCP segments (partial header reads).
 48→/// Returns byte count or null on error/EOF.
 49→/// TigerStyle: Standalone function for partial read accumulation.
 50→pub fn readMoreData(io: Io, stream: Io.net.Stream, remaining_buf: []u8) ?usize {
 51→    // Precondition: buffer must have space for more data
 52→    assert(remaining_buf.len > 0);
 53→
 54→    var reader_buf: [1]u8 = std.mem.zeroes([1]u8);
 55→    var reader = stream.reader(io, &reader_buf);
 56→    var bufs: [1][]u8 = .{remaining_buf};
 57→    const n = reader.interface.readVec(&bufs) catch |err| {
 58→        if (err != error.EndOfStream) {
 59→            debugLog("Read more error: {s}", .{@errorName(err)});
 60→        }
 61→        return null;
 62→    };
 63→
 64→    // Postcondition: returns actual bytes read (may be 0 on EOF)
 65→    return n;
 66→}
 67→
 68→/// Get body length from Content-Length header, or 0 if not present.
 69→/// TigerStyle: Explicit handling of missing header (no body).
 70→pub fn getBodyLength(request: *const Request) usize {
 71→    // Precondition: request must be valid
 72→    assert(@intFromPtr(request) != 0);
 73→
 74→    const cl_header = request.headers.get("Content-Length") orelse return 0;
 75→    const cl_value = parseContentLengthValue(cl_header) orelse return 0;
 76→
 77→    // Postcondition: result fits in usize (bounded cast)
 78→    return if (cl_value <= std.math.maxInt(usize)) @intCast(cl_value) else 0;
 79→}
