 98→    var request = Request{};
 99→    try request.headers.put("Content-Length", "invalid");
100→
101→    try std.testing.expectEqual(@as(usize, 0), getBodyLength(&request));
102→}
103→
104→test "getBodyLength returns 0 for empty Content-Length" {
105→    var request = Request{};
106→    try request.headers.put("Content-Length", "");
107→
108→    try std.testing.expectEqual(@as(usize, 0), getBodyLength(&request));
109→}
