  1→// lib/serval-server/h1/connection.zig
  2→//! HTTP/1.1 Connection Utilities
  3→//!
  4→//! Connection lifecycle management: unique IDs, keep-alive detection,
  5→//! and request processing state.
  6→//!
  7→//! TigerStyle: Explicit state management, no hidden globals in public API.
  8→
  9→const std = @import("std");
 10→const assert = std.debug.assert;
 11→
 12→const serval_core = @import("serval-core");
 13→const HeaderMap = serval_core.types.HeaderMap;
 14→
 15→// =============================================================================
 16→// Connection State
 17→// =============================================================================
 18→
 19→/// Global connection counter for unique connection IDs.
 20→/// TigerStyle: Module-level state with atomic access, monotonic ordering sufficient.
 21→/// u32 to support 32-bit targets (e.g. arm-linux-musleabihf) where 64-bit atomics
 22→/// are not available. Wraps after ~4 billion connections which is acceptable.
 23→var global_connection_id: std.atomic.Value(u32) = std.atomic.Value(u32).init(0);
 24→
 25→/// Result of processing a single HTTP request.
 26→/// TigerStyle: Explicit enum for control flow, no magic booleans.
 27→pub const ProcessResult = enum {
 28→    keep_alive,
 29→    close_connection,
 30→    fatal_error,
 31→};
 32→
 33→// =============================================================================
 34→// Connection Functions
 35→// =============================================================================
 36→
 37→/// Generate a unique connection ID.
 38→/// Thread-safe via atomic increment, monotonically increasing.
 39→/// TigerStyle: Wraps module-level state with explicit function.
 40→pub fn nextConnectionId() u64 {
 41→    // Postcondition: returned ID is unique (monotonic counter)
 42→    const id = global_connection_id.fetchAdd(1, .monotonic);
 43→    return @intCast(id);
 44→}
 45→
 46→/// Check if client requested connection close (RFC 9112).
 47→/// HTTP/1.1 defaults to keep-alive, only close if explicitly requested.
 48→///
 49→/// Returns true if Connection header is present and equals "close" (case-insensitive).
 50→pub fn clientWantsClose(headers: *const HeaderMap) bool {
 51→    // Precondition: headers pointer is valid
 52→    assert(@intFromPtr(headers) != 0);
 53→
 54→    const conn = headers.get("Connection") orelse return false;
 55→
 56→    // Postcondition: only returns true for exact "close" match
 57→    // "close" is exactly 5 characters
 58→    if (conn.len != 5) return false;
 59→    return std.ascii.eqlIgnoreCase(conn, "close");
 60→}
 61→
 62→// =============================================================================
 63→// Tests
 64→// =============================================================================
 65→
 66→test "nextConnectionId returns monotonically increasing values" {
 67→    const id1 = nextConnectionId();
 68→    const id2 = nextConnectionId();
 69→    const id3 = nextConnectionId();
 70→
 71→    try std.testing.expect(id2 > id1);
 72→    try std.testing.expect(id3 > id2);
 73→}
 74→
 75→test "clientWantsClose returns false for missing header" {
 76→    var headers = HeaderMap{};
 77→    try std.testing.expect(!clientWantsClose(&headers));
 78→}
 79→
 80→test "clientWantsClose returns true for 'close' header" {
 81→    var headers = HeaderMap{};
 82→    try headers.put("Connection", "close");
 83→    try std.testing.expect(clientWantsClose(&headers));
 84→}
 85→
 86→test "clientWantsClose is case-insensitive" {
 87→    var headers = HeaderMap{};
 88→
 89→    try headers.put("Connection", "Close");
 90→    try std.testing.expect(clientWantsClose(&headers));
 91→
 92→    try headers.put("Connection", "CLOSE");
 93→    try std.testing.expect(clientWantsClose(&headers));
 94→
 95→    try headers.put("Connection", "cLoSe");
 96→    try std.testing.expect(clientWantsClose(&headers));
 97→}
 98→
 99→test "clientWantsClose returns false for keep-alive" {
100→    var headers = HeaderMap{};
101→    try headers.put("Connection", "keep-alive");
102→    try std.testing.expect(!clientWantsClose(&headers));
103→}
104→
105→test "clientWantsClose returns false for wrong length values" {
106→    var headers = HeaderMap{};
107→
108→    // Too short
109→    try headers.put("Connection", "clos");
110→    try std.testing.expect(!clientWantsClose(&headers));
111→
112→    // Too long
113→    try headers.put("Connection", "closed");
114→    try std.testing.expect(!clientWantsClose(&headers));
115→
116→    // Empty
117→    try headers.put("Connection", "");
118→    try std.testing.expect(!clientWantsClose(&headers));
119→}
120→

  1→// lib/serval-http/parser.zig
  2→//! HTTP/1.1 Parser
  3→//!
  4→//! Zero-allocation HTTP/1.1 request parser.
  5→//! TigerStyle: Fixed-size buffers, explicit sizes, ~2 assertions per function.
  6→
  7→const std = @import("std");
  8→const assert = std.debug.assert;
  9→const serval_core = @import("serval-core");
 10→const types = serval_core.types;
 11→const config = serval_core.config;
 12→const errors = serval_core.errors;
 13→
 14→const Request = types.Request;
 15→const Method = types.Method;
 16→const Version = types.Version;
 17→const HeaderMap = types.HeaderMap;
 18→const BodyFraming = types.BodyFraming;
 19→const ParseError = errors.ParseError;
 20→
 21→// =============================================================================
 22→// Parser
 23→// =============================================================================
 24→
 25→pub const Parser = struct {
 26→    request: Request = .{},
 27→    headers_end: usize = 0, // byte offset after \r\n\r\n
 28→    body_framing: BodyFraming = .none, // determined by Transfer-Encoding or Content-Length
 29→
 30→    pub fn init() Parser {
 31→        return .{};
 32→    }
 33→
 34→    pub fn reset(self: *Parser) void {
 35→        self.request = .{};
 36→        self.headers_end = 0;
 37→        self.body_framing = .none;
 38→    }
 39→
 40→    /// Parse HTTP/1.1 request headers from buffer.
 41→    /// Buffer must contain complete headers (up to \r\n\r\n).
 42→    /// Returns slice pointing into input buffer (zero-copy).
 43→    pub fn parseHeaders(self: *Parser, buffer: []const u8) ParseError!void {
 44→        if (buffer.len == 0) return error.EmptyRequest;
 45→        if (buffer.len > config.MAX_HEADER_SIZE_BYTES) return error.HeadersTooLarge;
 46→
 47→        const headers_end_pos = std.mem.indexOf(u8, buffer, "\r\n\r\n") orelse
 48→            return error.MalformedHeader;
 49→
 50→        self.headers_end = headers_end_pos + 4; // byte offset after \r\n\r\n
 51→
 52→        const first_line_end = std.mem.indexOf(u8, buffer, "\r\n") orelse
 53→            return error.MalformedRequestLine;
 54→
 55→        try self.parseRequestLine(buffer[0..first_line_end]);
 56→
 57→        if (first_line_end + 2 < headers_end_pos) {
 58→            try self.parseHeaderLines(buffer[first_line_end + 2 .. headers_end_pos]);
 59→        }
 60→
 61→        // RFC 7230 Section 5.4: HTTP/1.1 requests MUST contain a Host header.
 62→        // HTTP/1.0 does not require Host, so we only enforce this for 1.1.
 63→        if (self.request.version == .@"HTTP/1.1") {
 64→            if (self.request.headers.getHost() == null) {
 65→                return error.MissingHostHeader;
 66→            }
 67→        }
 68→
 69→        // Validate message framing to prevent request smuggling attacks.
 70→        // Must be called after headers are parsed but before processing body.
 71→        try self.validateMessageFraming();
 72→
 73→        assert(self.request.path.len > 0);
 74→        assert(self.request.headers.count <= config.MAX_HEADERS);
 75→    }
 76→
 77→    fn parseRequestLine(self: *Parser, line: []const u8) ParseError!void {
 78→        if (line.len == 0) return error.EmptyRequest;
 79→        assert(line.len <= config.MAX_HEADER_SIZE_BYTES);
 80→
 81→        // RFC 7230 Section 3.1.1: Request line uses SP (space, 0x20) as delimiter.
 82→        // HTAB (0x09) in request line would be included in a token and fail validation
 83→        // (method lookup fails, URI validation rejects control chars).
 84→        // splitScalar on ' ' produces empty strings for multiple consecutive spaces.
 85→        var iter = std.mem.splitScalar(u8, line, ' ');
 86→
 87→        const method_str = iter.next() orelse return error.MalformedRequestLine;
 88→        // Empty method = leading space or multiple spaces before method
 89→        if (method_str.len == 0) return error.MalformedRequestLine;
 90→        self.request.method = parseMethod(method_str) orelse return error.InvalidMethod;
 91→
 92→        const uri_str = iter.next() orelse return error.MalformedRequestLine;
 93→        // Empty URI = multiple spaces between method and URI
 94→        if (uri_str.len == 0) return error.MalformedRequestLine;
 95→        if (uri_str.len > config.MAX_URI_LENGTH_BYTES) return error.UriTooLong;
 96→
 97→        // Check for asterisk-form (OPTIONS * HTTP/1.1) per RFC 7230 Section 5.3.4
 98→        if (uri_str.len == 1 and uri_str[0] == '*') {
 99→            // Only OPTIONS method allows asterisk-form request-target
100→            if (self.request.method != .OPTIONS) {
101→                return error.InvalidUri;
102→            }
103→            self.request.path = uri_str;
104→        } else {
105→            // Origin-form must start with '/'
106→            if (uri_str[0] != '/') return error.InvalidUri;
107→
108→            for (uri_str) |ch| {
109→                if (ch <= 0x1F or ch == 0x7F or ch == ' ') return error.InvalidUri;
110→            }
111→            self.request.path = uri_str;
112→        }
113→
114→        const version_str = iter.next() orelse return error.MalformedRequestLine;
115→        // Empty version = multiple spaces between URI and version
116→        if (version_str.len == 0) return error.MalformedRequestLine;
117→        self.request.version = parseVersion(version_str) orelse return error.InvalidHttpVersion;
118→
119→        if (iter.next() != null) return error.MalformedRequestLine;
120→
121→        assert(self.request.path.len > 0);
122→    }
123→
124→    fn parseHeaderLines(self: *Parser, buffer: []const u8) ParseError!void {
125→        assert(self.request.headers.count == 0);
126→
127→        var lines = std.mem.splitSequence(u8, buffer, "\r\n");
128→
129→        // TigerStyle: Bounded loop - limit iterations to MAX_HEADERS + 1
130→        // (extra 1 for potential empty lines between headers)
131→        var line_count: u8 = 0;
132→        const max_lines: u8 = config.MAX_HEADERS + 1;
133→
134→        while (lines.next()) |line| : (line_count += 1) {
135→            if (line_count >= max_lines) return error.TooManyHeaders;
136→            if (line.len == 0) continue;
137→
138→            // RFC 7230 Section 3.2.4: obs-fold (line continuation with leading SP/HTAB)
139→            // is deprecated and MUST be rejected to prevent request smuggling.
140→            // Attackers use obs-fold to hide headers from proxies that don't unfold.
141→            if (line[0] == 0x20 or line[0] == 0x09) {
142→                return error.MalformedHeader;
143→            }
144→
145→            const colon_pos = std.mem.indexOfScalar(u8, line, ':') orelse
146→                return error.MalformedHeader;
147→
148→            if (colon_pos == 0) return error.InvalidHeaderName;
149→
150→            const name = line[0..colon_pos];

