  2→//! Per-Request Context
  3→//!
  4→//! Passed to all handler hooks. Allows sharing state within request lifecycle.
  5→//! TigerStyle: Fixed-size, no allocation.
  6→
  7→const std = @import("std");
  8→const assert = std.debug.assert;
  9→const types = @import("types.zig");
 10→const time = @import("time.zig");
 11→const span_handle_mod = @import("span_handle.zig");
 12→const config = @import("config.zig");
 13→const Upstream = types.Upstream;
 14→const SpanHandle = span_handle_mod.SpanHandle;
 15→const BodyFraming = types.BodyFraming;
 16→
 17→// =============================================================================
 18→// BodyReader - Lazy Body Reading
 19→// =============================================================================
 20→
 21→/// BodyReader enables lazy request body reading in direct response handlers.
 22→///
 23→/// Industry standard pattern: Body is only read when handler explicitly requests it.
 24→/// This avoids reading large request bodies that may not be needed (e.g., rejecting
 25→/// requests based on headers alone).
 26→///
 27→/// TigerStyle: No allocation, uses caller-provided buffer, bounded by content_length.
 28→///
 29→/// Example usage in onRequest hook:
 30→/// ```zig
 31→/// pub fn onRequest(self: *@This(), ctx: *serval.Context, request: *serval.Request, response_buf: []u8) serval.Action {
 32→///     var body_buf: [8192]u8 = undefined;
 33→///     const body = ctx.readBody(&body_buf) catch |err| {
 34→///         return .{ .reject = .{ .status = 400, .reason = "Body read failed" } };
 35→///     };
 36→///     // Process body...
 37→/// }
 38→/// ```
 39→pub const BodyReader = struct {
 40→    /// Body framing mode (content_length, chunked, or none).
 41→    framing: BodyFraming,
 42→
 43→    /// Number of body bytes already read into initial buffer.
 44→    /// These bytes are in initial_body and must be copied first.
 45→    bytes_already_read: u64,
 46→
 47→    /// Initial body bytes already in request buffer (after headers).
 48→    /// Points into server's recv_buf - valid only for this request.
 49→    initial_body: []const u8,
 50→
 51→    /// Opaque pointer to server-specific read context (TLS stream, io, etc.).
 52→    /// TigerStyle: Erased pointer to avoid generics leaking into serval-core.
 53→    read_ctx: ?*anyopaque,
 54→
 55→    /// Function pointer for reading more data from the connection.
 56→    /// Returns number of bytes read into buf, or null on error/EOF.
 57→    /// TigerStyle: Function pointer enables server to provide platform-specific I/O.
 58→    read_fn: ?*const fn (ctx: *anyopaque, buf: []u8) ?usize,
 59→
 60→    /// Total bytes read so far (including initial_body).
 61→    total_bytes_read: u64 = 0,
 62→
 63→    /// Whether initial body has been consumed.
 64→    initial_consumed: bool = false,
 65→
 66→    /// Read request body into provided buffer.
 67→    ///
 68→    /// Returns slice of body data read into buf.
 69→    /// Multiple calls will read more data (for chunked or large bodies).
 70→    ///
 71→    /// TigerStyle: Bounded by content_length if present, caller provides buffer.
 72→    ///
 73→    /// Arguments:
 74→    ///   buf: Buffer to read body into. Must be large enough for expected body.
 75→    ///
 76→    /// Returns:
 77→    ///   - Slice of buf containing body data read.
 78→    ///   - Empty slice if no body or body fully read.
 79→    ///
 80→    /// Errors:
 81→    ///   - error.BodyReaderNotConfigured: read_fn not set (server doesn't support lazy reading).
 82→    ///   - error.BodyTooLarge: Content-Length exceeds buf size.
 83→    ///   - error.ReadFailed: I/O error during read.
 84→    pub fn read(self: *BodyReader, buf: []u8) ![]const u8 {
 85→        // S1: Precondition - buffer must be provided
 86→        assert(buf.len > 0);
 87→
 88→        // Handle body framing modes
 89→        switch (self.framing) {
 90→            .none => return buf[0..0], // No body expected
 91→            .chunked => return error.ChunkedNotSupported, // Chunked requires streaming
 92→            .content_length => |content_length| {
 93→                // S1: Precondition - check bounds
 94→                if (content_length > buf.len) return error.BodyTooLarge;
 95→                if (content_length == 0) return buf[0..0];
 96→
 97→                const body_len: usize = @intCast(content_length);
 98→
 99→                // Copy initial body bytes first (if not already consumed)
100→                var dest_offset: usize = 0;
101→                if (!self.initial_consumed and self.initial_body.len > 0) {
102→                    const copy_len = @min(self.initial_body.len, body_len);
103→                    @memcpy(buf[0..copy_len], self.initial_body[0..copy_len]);
104→                    dest_offset = copy_len;
105→                    self.initial_consumed = true;
106→                    self.total_bytes_read = copy_len;
107→                }
108→
109→                // Read remaining body bytes if needed
110→                if (dest_offset < body_len) {
111→                    const read_ctx = self.read_ctx orelse return error.BodyReaderNotConfigured;
112→                    const read_fn = self.read_fn orelse return error.BodyReaderNotConfigured;
113→
114→                    // S3: Bounded loop - max iterations based on 1KB minimum read assumption
115→                    // For 128MB max body size, worst case is 128K iterations
116→                    const max_iterations: u32 = 256 * 1024;
117→                    var iterations: u32 = 0;
118→
119→                    while (dest_offset < body_len and iterations < max_iterations) {
120→                        iterations += 1;
121→
122→                        const remaining = body_len - dest_offset;
123→                        const n = read_fn(read_ctx, buf[dest_offset..][0..remaining]) orelse {
124→                            return error.ReadFailed;
125→                        };
126→                        if (n == 0) return error.ReadFailed; // Unexpected EOF
127→
128→                        dest_offset += n;
129→                        self.total_bytes_read += n;
130→                    }
131→
132→                    // S3: Check loop bound wasn't exceeded
133→                    if (iterations >= max_iterations and dest_offset < body_len) {
134→                        return error.ReadFailed;
135→                    }
136→                }
137→
138→                // S2: Postcondition - read exactly content_length bytes
139→                assert(dest_offset == body_len);
140→                return buf[0..body_len];
141→            },
142→        }
143→    }
144→
145→    /// Read one chunk of body data (up to buf.len bytes).
146→    /// Returns null when body is fully consumed.
147→    /// TigerStyle: Enables incremental body reading for large uploads without full buffering.
148→    ///
149→    /// Use this for streaming large bodies where buffering the entire body is impractical.
150→    /// Each call returns the next chunk of data, empty slice signals end of body.
151→    pub fn readChunk(self: *BodyReader, buf: []u8) !?[]const u8 {
152→        // S1: Precondition - buffer must be provided
153→        assert(buf.len > 0);
154→
155→        // Handle body framing modes
156→        switch (self.framing) {
157→            .none => return null, // No body expected
158→            .chunked => return error.ChunkedNotSupported, // Chunked requires different handling
159→            .content_length => |content_length| {
160→                // Check if we've read everything
161→                if (self.total_bytes_read >= content_length) {
162→                    return null; // Body fully consumed
163→                }
164→
165→                // First, return any unconsumed initial body bytes
166→                if (!self.initial_consumed and self.initial_body.len > 0) {
167→                    const remaining_content: u64 = content_length - self.total_bytes_read;
168→                    const initial_remaining = self.initial_body.len - @as(usize, @intCast(@min(self.total_bytes_read, self.initial_body.len)));
169→                    const copy_len = @min(@min(initial_remaining, buf.len), @as(usize, @intCast(remaining_content)));
170→
171→                    if (copy_len > 0) {
172→                        const start = self.initial_body.len - initial_remaining;
173→                        @memcpy(buf[0..copy_len], self.initial_body[start..][0..copy_len]);
174→                        self.total_bytes_read += copy_len;
175→
176→                        if (self.total_bytes_read >= self.initial_body.len) {
177→                            self.initial_consumed = true;
178→                        }
179→                        return buf[0..copy_len];
180→                    }
181→                    self.initial_consumed = true;
182→                }
183→
184→                // Read from socket
185→                const remaining: u64 = content_length - self.total_bytes_read;
186→                if (remaining == 0) return null;
187→
188→                const read_ctx = self.read_ctx orelse return error.BodyReaderNotConfigured;
189→                const read_fn = self.read_fn orelse return error.BodyReaderNotConfigured;
190→
191→                const to_read: usize = @intCast(@min(remaining, buf.len));
192→                const n = read_fn(read_ctx, buf[0..to_read]) orelse {
193→                    return error.ReadFailed;
194→                };
195→                if (n == 0) return error.ReadFailed; // Unexpected EOF
196→
197→                self.total_bytes_read += n;
198→                return buf[0..n];
199→            },
200→        }
201→    }
202→
203→    /// Check if body reading is available.
204→    /// TigerStyle: Explicit availability check.
205→    pub fn isAvailable(self: *const BodyReader) bool {
206→        return self.read_fn != null and self.read_ctx != null;
207→    }
208→
209→    /// Get expected body length if known.
210→    /// TigerStyle: Trivial accessor, no assertions needed.
211→    pub fn getContentLength(self: *const BodyReader) ?u64 {
212→        return self.framing.getContentLength();
213→    }
214→};
215→
216→/// Errors that can occur during body reading.
217→/// TigerStyle: Explicit error set with all possible body read failures.
218→pub const BodyReadError = error{
219→    /// BodyReader not available - server hasn't set up body reader.
220→    BodyReaderNotAvailable,
221→    /// BodyReader not configured - read function not set.
222→    BodyReaderNotConfigured,
223→    /// Content-Length exceeds provided buffer size.
224→    BodyTooLarge,
225→    /// I/O error or unexpected EOF during read.
226→    ReadFailed,
227→    /// Chunked transfer encoding not supported for lazy reading.
228→    ChunkedNotSupported,
229→};
230→
231→pub const Context = struct {
232→    // Timing - i128 matches std.time.Instant.timestamp/realtimeNanos() return type,
233→    // which can represent nanoseconds since epoch including pre-1970 dates.
234→    start_time_ns: i128 = 0,
235→
236→    // Request metadata
237→    request_id: u64 = 0,
238→
239→    // User-defined storage - caller owns lifetime; must remain valid for request duration.
240→    // Server does not free or manage this pointer.
241→    user_data: ?*anyopaque = null,
242→
243→    // Set after selectUpstream
244→    upstream: ?Upstream = null,
245→
246→    // Set by router when route matches with strip_prefix=true.
247→    // Points to slice of original request path (zero-copy).
248→    // If null, forwarder uses original request path.
249→    rewritten_path: ?[]const u8 = null,
250→
251→    // Metrics (updated by server)
252→    bytes_received: u64 = 0,
253→    bytes_sent: u64 = 0,
254→
255→    // Response status (set after response)
256→    response_status: u16 = 0,
257→    duration_ns: u64 = 0,
258→
259→    // Error tracking - points to comptime string literal from @errorName().
260→    // Valid for program lifetime (static string table).
261→    error_name: ?[]const u8 = null,
262→
263→    // Connection-scoped fields (set once per connection, preserved across requests)
264→    connection_id: u64 = 0,
265→    connection_start_ns: i128 = 0,
266→    request_number: u32 = 0,
267→    client_addr: [46]u8 = std.mem.zeroes([46]u8),
268→    client_port: u16 = 0,
269→
270→    // Request timing
271→    parse_duration_ns: u64 = 0,
272→
273→    // Tracing - span handle for the current request
274→    // Set by server, can be used by handlers to create child spans.
275→    // TigerStyle: Fixed-size (32 bytes), no allocation.
276→    span_handle: SpanHandle = .{},
277→
278→    // Body reader for lazy body reading in direct response handlers.
279→    // Set by server before calling onRequest hook.
280→    // TigerStyle: Optional pointer - null means body reading not available.
281→    _body_reader: ?*BodyReader = null,
282→
283→    pub fn init() Context {
284→        const ctx = Context{
285→            .start_time_ns = time.realtimeNanos(),
286→        };
287→
288→        // Postcondition: time must be valid (realtimeNanos always returns positive nanoseconds)
289→        std.debug.assert(ctx.start_time_ns > 0);
290→
291→        return ctx;
292→    }
293→
294→    /// Reset context for a new request while preserving connection-scoped fields.
295→    /// Connection-scoped fields (connection_id, connection_start_ns, client_addr,
296→    /// client_port) are preserved. Per-request fields are reset, and request_number
297→    /// is incremented.
298→    pub fn reset(self: *Context) void {
299→        // Preserve connection-scoped fields
300→        const connection_id = self.connection_id;
301→        const connection_start_ns = self.connection_start_ns;
302→        const client_addr = self.client_addr;
303→        const client_port = self.client_port;
304→        const request_number = self.request_number;
305→
306→        // Reset all fields to defaults
307→        self.* = .{
308→            .start_time_ns = time.realtimeNanos(),
309→        };
310→
311→        // Restore connection-scoped fields
312→        self.connection_id = connection_id;
313→        self.connection_start_ns = connection_start_ns;
314→        self.client_addr = client_addr;
315→        self.client_port = client_port;
316→        self.request_number = request_number + 1;
317→
318→        // Postcondition: connection-scoped fields preserved, per-request fields reset
319→        assert(self.connection_id == connection_id);
320→        assert(self.bytes_received == 0 and self.response_status == 0);
321→    }
322→
323→    /// Read request body into provided buffer.
324→    ///
325→    /// This enables lazy body reading - body is only read when handler explicitly
326→    /// requests it. Industry standard pattern used by Express.js, Go's http.Request, etc.
327→    ///
328→    /// TigerStyle: Caller provides buffer, bounded by Content-Length.
329→    ///
330→    /// Arguments:
331→    ///   buf: Buffer to read body into. Should be at least as large as expected
332→    ///        Content-Length. Use config.DIRECT_REQUEST_BODY_SIZE_BYTES as max.
333→    ///
334→    /// Returns:
335→    ///   - Slice of buf containing body data.
336→    ///   - Empty slice if no body present.
337→    ///
338→    /// Errors:
339→    ///   - error.BodyReaderNotAvailable: Server hasn't set up body reader.
340→    ///   - error.BodyTooLarge: Content-Length exceeds buffer size.
341→    ///   - error.ReadFailed: I/O error during read.
342→    ///   - error.ChunkedNotSupported: Chunked transfer encoding not supported.
343→    ///
344→    /// Example:
345→    /// ```zig
346→    /// var body_buf: [config.DIRECT_REQUEST_BODY_SIZE_BYTES]u8 = undefined;
347→    /// const body = ctx.readBody(&body_buf) catch |err| {
348→    ///     return .{ .reject = .{ .status = 400, .reason = "Body read failed" } };
349→    /// };
350→    /// ```
351→    pub fn readBody(self: *Context, buf: []u8) BodyReadError![]const u8 {
352→        // S1: Precondition - buffer must be provided
353→        assert(buf.len > 0);
354→
355→        const reader = self._body_reader orelse return error.BodyReaderNotAvailable;
356→        return reader.read(buf);
357→    }
358→
359→    /// Read one chunk of body data (up to buf.len bytes).
360→    /// Returns null when body is fully consumed.
361→    /// TigerStyle: Enables incremental body reading for large uploads (>4GB) without full buffering.
362→    ///
363→    /// Example:
364→    /// ```zig
365→    /// var chunk_buf: [65536]u8 = undefined;
366→    /// var total: u64 = 0;
367→    /// while (try ctx.readBodyChunk(&chunk_buf)) |chunk| {
368→    ///     total += chunk.len;
369→    /// }
370→    /// ```
371→    pub fn readBodyChunk(self: *Context, buf: []u8) BodyReadError!?[]const u8 {
372→        // S1: Precondition - buffer must be provided
373→        assert(buf.len > 0);
374→
375→        const reader = self._body_reader orelse return error.BodyReaderNotAvailable;
376→        return reader.readChunk(buf);
377→    }
378→
379→    /// Check if body reading is available for this request.
380→    /// TigerStyle: Explicit availability check before attempting read.
381→    pub fn canReadBody(self: *const Context) bool {
382→        const reader = self._body_reader orelse return false;
383→        return reader.isAvailable();
384→    }
385→
386→    /// Get expected body length if known (from Content-Length header).
387→    /// Returns null for chunked encoding or no body.
388→    /// TigerStyle: Useful for pre-checking buffer size requirements.
389→    pub fn getBodyLength(self: *const Context) ?u64 {
390→        const reader = self._body_reader orelse return null;
391→        return reader.getContentLength();
392→    }
393→};
