401→test "Context reset preserves connection-scoped fields" {
402→    var ctx = Context.init();
403→
404→    // Set connection-scoped fields
405→    ctx.connection_id = 12345;
406→    ctx.connection_start_ns = 9999;
407→    ctx.client_addr[0] = '1';
408→    ctx.client_addr[1] = '2';
409→    ctx.client_addr[2] = '7';
410→    ctx.client_port = 8080;
411→    ctx.request_number = 5;
412→
413→    // Set per-request fields that should be reset
414→    ctx.bytes_received = 1000;
415→    ctx.parse_duration_ns = 500;
416→    ctx.response_status = 200;
417→    ctx.rewritten_path = "/api/users";
418→
419→    // Reset for new request
420→    ctx.reset();
421→
422→    // Connection-scoped fields should be preserved
423→    try std.testing.expectEqual(@as(u64, 12345), ctx.connection_id);
424→    try std.testing.expectEqual(@as(i128, 9999), ctx.connection_start_ns);
425→    try std.testing.expectEqual(@as(u8, '1'), ctx.client_addr[0]);
426→    try std.testing.expectEqual(@as(u8, '2'), ctx.client_addr[1]);
427→    try std.testing.expectEqual(@as(u8, '7'), ctx.client_addr[2]);
428→    try std.testing.expectEqual(@as(u16, 8080), ctx.client_port);
429→
430→    // Request number should be incremented
431→    try std.testing.expectEqual(@as(u32, 6), ctx.request_number);
432→
433→    // Per-request fields should be reset
434→    try std.testing.expectEqual(@as(u64, 0), ctx.bytes_received);
435→    try std.testing.expectEqual(@as(u64, 0), ctx.parse_duration_ns);
436→    try std.testing.expectEqual(@as(u16, 0), ctx.response_status);
437→    try std.testing.expectEqual(@as(?[]const u8, null), ctx.rewritten_path);
438→
439→    // Start time should be refreshed
440→    try std.testing.expect(ctx.start_time_ns > 0);
441→
442→    // Body reader should be reset to null
443→    try std.testing.expectEqual(@as(?*BodyReader, null), ctx._body_reader);
444→}
