184→    /// Validates message framing and determines body_framing after header parsing.
185→    /// RFC 7230 Section 3.3.3: Reject ambiguous message length indicators.
186→    /// TigerStyle: Security checks as explicit validation step, ~2 assertions.
187→    fn validateMessageFraming(self: *Parser) ParseError!void {
188→        const content_length_str = self.request.headers.getContentLength();
189→        const transfer_encoding = self.request.headers.getTransferEncoding();
190→
191→        // CL-TE/TE-CL smuggling prevention: Both headers present is ambiguous.
192→        // Different intermediaries may interpret the body length differently,
193→        // allowing attackers to smuggle requests past security controls.
194→        if (content_length_str != null and transfer_encoding != null) {
195→            return error.AmbiguousMessageLength;
196→        }
197→
198→        // Determine body framing per RFC 9112 Section 6.
199→        // Priority: Transfer-Encoding > Content-Length > none
200→        if (transfer_encoding) |te| {
201→            if (containsIgnoreCase(te, "chunked")) {
202→                self.body_framing = .chunked;
203→            } else {
204→                // Non-chunked Transfer-Encoding (e.g., "identity") has no body framing.
205→                // Per RFC 9112 Section 6.1, "identity" is obsolete and MUST NOT be sent.
206→                self.body_framing = .none;
207→            }
208→        } else if (content_length_str) |cl_str| {
209→            const content_length = parseContentLengthValue(cl_str) orelse
210→                return error.InvalidContentLength;
211→            self.body_framing = .{ .content_length = content_length };
212→        } else {
213→            self.body_framing = .none;
214→        }
215→
216→        assert(self.body_framing == .chunked or
217→            self.body_framing == .none or
218→            self.body_framing.hasKnownLength());
219→    }
220→};
