245→/// Case-insensitive substring search.
246→/// Returns true if needle is found within haystack (case-insensitive).
247→/// TigerStyle: Bounded loop - iterations limited by haystack length.
248→fn containsIgnoreCase(haystack: []const u8, needle: []const u8) bool {
249→    if (needle.len == 0) return true;
250→    if (haystack.len < needle.len) return false;
251→
252→    const search_range = haystack.len - needle.len + 1;
253→    for (0..search_range) |i| {
254→        if (std.ascii.eqlIgnoreCase(haystack[i..][0..needle.len], needle)) {
255→            return true;
256→        }
257→    }
258→    return false;
259→}
