265→/// Parse HTTP status code from response line.
266→/// Expects "HTTP/1.x NNN Reason" format.
267→/// Returns null for invalid format or out-of-range status.
268→/// TigerStyle: Bounded loop, explicit size checks.
269→pub fn parseStatusCode(header: []const u8) ?u16 {
270→    if (header.len < 12) return null; // "HTTP/1.1 200" minimum
271→
272→    // Find first space after HTTP version
273→    const space_idx = std.mem.indexOfScalar(u8, header, ' ') orelse return null;
274→    if (space_idx + 4 > header.len) return null;
275→
276→    const status_start = space_idx + 1;
277→    const status_str = header[status_start..][0..3];
278→
279→    var result: u16 = 0;
280→    for (status_str) |ch| {
281→        if (ch < '0' or ch > '9') return null;
282→        result = result * 10 + (ch - '0');
283→    }
284→
285→    if (result < 100 or result > 599) return null;
286→
287→    assert(result >= 100 and result <= 599);
288→    return result;
289→}
