291→/// Parse Content-Length header value from a raw header block.
292→/// Searches for Content-Length header (case-insensitive) and extracts value.
293→/// Returns null if not found, invalid, or has leading zeros.
294→/// TigerStyle: Returns u64 for Content-Length (can exceed 4GB), bounded loops.
295→pub fn parseContentLength(header: []const u8) ?u64 {
296→    const header_name = "content-length:";
297→    if (header.len < header_name.len) return null;
298→
299→    var search_pos: usize = 0;
300→    const max_iterations: u32 = config.MAX_HEADER_SIZE_BYTES;
301→    var iterations: u32 = 0;
302→
303→    while (search_pos + header_name.len <= header.len and iterations < max_iterations) : (iterations += 1) {
304→        const candidate = header[search_pos..][0..header_name.len];
305→
306→        if (std.ascii.eqlIgnoreCase(candidate, header_name)) {
307→            var value_start = search_pos + header_name.len;
308→
309→            // Skip optional whitespace after colon.
310→            while (value_start < header.len and (header[value_start] == ' ' or header[value_start] == '\t')) {
311→                value_start += 1;
312→            }
313→
314→            // Find end of value (until \r, \n, or end).
315→            var value_end = value_start;
316→            while (value_end < header.len and header[value_end] != '\r' and header[value_end] != '\n') {
317→                value_end += 1;
318→            }
319→
320→            if (value_end > value_start) {
321→                return parseContentLengthValue(header[value_start..value_end]);
322→            }
323→            return null;
324→        }
325→
326→        // Move to next line.
327→        if (std.mem.indexOfScalar(u8, header[search_pos..], '\n')) |newline_offset| {
328→            search_pos += newline_offset + 1;
329→        } else {
330→            break;
331→        }
332→    }
333→
334→    return null;
335→}
336→
337→/// Parse Content-Length value string to u64.
338→/// Returns null for empty, oversized (>20 digits), non-numeric, overflow, or leading zeros.
339→/// TigerStyle: Explicit overflow detection, no hidden behavior.
340→pub fn parseContentLengthValue(value: []const u8) ?u64 {
341→    if (value.len == 0) return null;
342→    if (value.len > 20) return null; // u64 max is 20 digits
343→
344→    // TigerStyle: Reject leading zeros (except single "0")
345→    // "007" is invalid, "0" is valid
346→    if (value.len > 1 and value[0] == '0') return null;
347→
348→    var result: u64 = 0;
349→    for (value) |ch| {
350→        if (ch < '0' or ch > '9') return null;
351→
352→        // Check for overflow on multiply
353→        const mul_result = @mulWithOverflow(result, 10);
354→        if (mul_result[1] != 0) return null;
355→
356→        // Check for overflow on add
357→        const add_result = @addWithOverflow(mul_result[0], ch - '0');
358→        if (add_result[1] != 0) return null;
359→
360→        result = add_result[0];
361→    }
362→    return result;
363→}
