  2→//! Body Transfer
  3→//!
  4→//! Zero-copy body streaming using splice (Linux) or buffered copy.
  5→//! Supports both Content-Length and chunked transfer encoding.
  6→//! TigerStyle: Platform selection at comptime, bounded loops.
  7→
  8→const std = @import("std");
  9→const assert = std.debug.assert;
 10→const builtin = @import("builtin");
 11→const posix = std.posix;
 12→const Io = std.Io;
 13→
 14→const proxy_types = @import("../types.zig");
 15→const ForwardError = proxy_types.ForwardError;
 16→const BodyInfo = proxy_types.BodyInfo;
 17→
 18→const request_mod = @import("request.zig");
