 24→const core = @import("serval-core");
 25→const closeFd = core.closeFd;
 26→const serval_time = core.time;
 27→const SPLICE_CHUNK_SIZE_BYTES = core.config.SPLICE_CHUNK_SIZE_BYTES;
 28→const COPY_CHUNK_SIZE_BYTES = core.config.COPY_CHUNK_SIZE_BYTES;
 29→
 30→const pool_mod = @import("serval-pool").pool;
 31→const Connection = pool_mod.Connection;
