 33→const serval_socket = @import("serval-socket");
 34→const Socket = serval_socket.Socket;
 35→
 36→// =============================================================================
 37→// Splice Constants (Linux)
 38→// =============================================================================
 39→
 40→/// SPLICE_F_MOVE: Move pages instead of copying (hint to kernel).
 41→const SPLICE_F_MOVE: u32 = 1;
 42→
 43→/// SPLICE_F_MORE: More data will be coming (enables TCP cork optimization).
 44→const SPLICE_F_MORE: u32 = 4;
 45→/// SPLICE_F_NONBLOCK: Non-blocking splice operation.
 46→const SPLICE_F_NONBLOCK: u32 = 2;
 47→
 48→/// Max no-progress interval before failing splice loops.
 49→const SPLICE_STALL_TIMEOUT_NS: u64 = 120 * serval_time.ns_per_s;
 50→/// Explicit bound on EAGAIN retries in splice loops.
 51→const SPLICE_MAX_RETRY_COUNT: u32 = 240_000;
 52→/// Poll timeout used when waiting for splice readability/writability.
 53→const SPLICE_POLL_TIMEOUT_MS: i32 = 250;
 54→
 55→// =============================================================================
 56→// Platform-Specific Body Forwarding
 57→// =============================================================================
 58→
 59→/// Forward response body using zero-copy splice (Linux) or buffered copy.
 60→/// Uses Socket abstraction for unified TLS/plaintext handling.
 61→/// When Io is provided, uses fiber-safe copy (io_uring-backed netRead/netWrite)
 62→/// to avoid blocking the fiber scheduler during concurrent body streaming.
 63→/// TigerStyle: Explicit TLS check via is_tls(), splice only for both plain.
 64→pub fn forwardBody(
 65→    upstream: *Socket,
 66→    client: *Socket,
 67→    length_bytes: u64,
 68→    io: ?Io,
 69→) ForwardError!u64 {
 70→    // Precondition: sockets have valid fds.
 71→    assert(upstream.get_fd() >= 0);
 72→    assert(client.get_fd() >= 0);
 73→
 74→    // When Io is available, use fiber-safe copy path (io_uring-backed netRead/netWrite).
 75→    // This avoids blocking the fiber scheduler with raw splice poll(), which deadlocks
 76→    // when running concurrently with the body-streaming background fiber on large payloads.
 77→    if (io) |runtime_io| {
 78→        const result = try forwardBodyCopyFiber(upstream, client, length_bytes, runtime_io);
 79→        assert(result <= length_bytes);
 80→        return result;
 81→    }
 82→
 83→    // No Io: use zero-copy splice (non-concurrent path only).
 84→    if (!upstream.is_tls() and !client.is_tls()) {
 85→        if (comptime builtin.os.tag == .linux) {
 86→            const result = try forwardBodySplice(upstream.get_fd(), client.get_fd(), length_bytes);
 87→            // Postcondition: forwarded at most requested bytes (may be less on EOF/error).
 88→            assert(result <= length_bytes);
 89→            return result;
 90→        }
 91→    }
 92→
 93→    // Userspace copy for any TLS involvement or non-Linux platforms.
 94→    const result = try forwardBodyCopy(upstream, client, length_bytes);
 95→
 96→    // Postcondition: forwarded at most requested bytes (may be less on EOF/error).
 97→    assert(result <= length_bytes);
 98→    return result;
 99→}
100→
101→// =============================================================================
102→// Linux Zero-Copy via Splice
103→// =============================================================================
104→
105→/// Raw splice syscall - transfers data between fds without userspace copy.
106→/// Uses direct syscall because std.os.linux.splice was removed in Zig 0.16.
107→fn spliceSyscall(fd_in: i32, fd_out: i32, len: usize, flags: u32) isize {
108→    assert(fd_in >= 0);
109→    assert(fd_out >= 0);
110→
111→    const linux = std.os.linux;
112→    return @bitCast(linux.syscall6(
113→        .splice,
114→        @as(usize, @bitCast(@as(isize, fd_in))),
115→        0, // off_in = null
116→        @as(usize, @bitCast(@as(isize, fd_out))),
117→        0, // off_out = null
118→        len,
119→        flags,
120→    ));
121→}
122→
123→fn isLinuxErrno(result: isize, errno_code: std.os.linux.E) bool {
124→    assert(result < 0);
125→    const errno_value: isize = @intCast(@intFromEnum(errno_code));
126→    return result == -errno_value;
127→}
128→
129→/// Forward body using Linux splice syscall for zero-copy transfer.
130→/// TigerStyle: Bounded loops, assertion on fd validity.
131→fn forwardBodySplice(upstream_fd: i32, client_fd: i32, length_bytes: u64) ForwardError!u64 {
132→    assert(upstream_fd >= 0);
133→    assert(client_fd >= 0);
134→
135→    // Create pipe for splice
136→    var pipe_fds: [2]c_int = undefined;
137→    if (std.c.pipe(&pipe_fds) != 0) {
138→        // Fallback to copy if pipe creation fails.
139→        // TigerStyle: Cannot use forwardBodyCopy here as we only have fds.
140→        return ForwardError.SpliceFailed;
141→    }
142→    defer {
143→        closeFd(pipe_fds[0]);
144→        closeFd(pipe_fds[1]);
145→    }
146→
147→    var upstream_flags = getFdFlags(upstream_fd) catch return ForwardError.SpliceFailed;
148→    var client_flags = getFdFlags(client_fd) catch return ForwardError.SpliceFailed;
149→    var pipe_read_flags = getFdFlags(pipe_fds[0]) catch return ForwardError.SpliceFailed;
150→    var pipe_write_flags = getFdFlags(pipe_fds[1]) catch return ForwardError.SpliceFailed;
151→    defer {
152→        setFdFlags(upstream_fd, upstream_flags) catch |err| {
153→            std.log.warn("splice restore flags failed fd={d} err={s}", .{ upstream_fd, @errorName(err) });
154→        };
155→        setFdFlags(client_fd, client_flags) catch |err| {
156→            std.log.warn("splice restore flags failed fd={d} err={s}", .{ client_fd, @errorName(err) });
157→        };
158→        setFdFlags(pipe_fds[0], pipe_read_flags) catch |err| {
159→            std.log.warn("splice restore flags failed fd={d} err={s}", .{ pipe_fds[0], @errorName(err) });
160→        };
161→        setFdFlags(pipe_fds[1], pipe_write_flags) catch |err| {
162→            std.log.warn("splice restore flags failed fd={d} err={s}", .{ pipe_fds[1], @errorName(err) });
163→        };
164→    }
165→
166→    setFdNonBlocking(upstream_fd, &upstream_flags) catch return ForwardError.SpliceFailed;
167→    setFdNonBlocking(client_fd, &client_flags) catch return ForwardError.SpliceFailed;
168→    setFdNonBlocking(pipe_fds[0], &pipe_read_flags) catch return ForwardError.SpliceFailed;
169→    setFdNonBlocking(pipe_fds[1], &pipe_write_flags) catch return ForwardError.SpliceFailed;
170→
171→    var forwarded_bytes: u64 = 0;
172→    // TigerStyle: explicit worst-case bound (1 byte forward progress per iteration).
173→    const max_iterations: u64 = length_bytes +| 1024;
174→    var iterations: u64 = 0;
175→    var retry_count: u32 = 0;
176→    var last_progress_ns: u64 = serval_time.monotonicNanos();
177→
178→    while (forwarded_bytes < length_bytes and iterations < max_iterations) : (iterations += 1) {
179→        const remaining_bytes = length_bytes - forwarded_bytes;
180→        const chunk_size: usize = @intCast(@min(remaining_bytes, SPLICE_CHUNK_SIZE_BYTES));
181→
182→        // Splice from upstream to pipe
183→        const to_pipe = spliceSyscall(upstream_fd, pipe_fds[1], chunk_size, SPLICE_F_MOVE | SPLICE_F_MORE | SPLICE_F_NONBLOCK);
184→
185→        if (to_pipe == 0) break;
186→        if (to_pipe < 0) {
187→            if (isLinuxErrno(to_pipe, .INTR)) continue;
188→            if (isLinuxErrno(to_pipe, .AGAIN)) {
189→                retry_count += 1;
190→                const now_ns = serval_time.monotonicNanos();
191→                if (retry_count >= SPLICE_MAX_RETRY_COUNT or
192→                    now_ns -| last_progress_ns >= SPLICE_STALL_TIMEOUT_NS)
193→                {
194→                    return ForwardError.SpliceFailed;
195→                }
196→                _ = waitForSpliceReady(upstream_fd, pipe_fds[1], posix.POLL.IN, posix.POLL.OUT, SPLICE_POLL_TIMEOUT_MS);
197→                continue;
198→            }
199→            return ForwardError.SpliceFailed;
200→        }
201→
202→        retry_count = 0;
203→        last_progress_ns = serval_time.monotonicNanos();
204→
205→        // Splice from pipe to client
206→        var pipe_sent_bytes: u64 = 0;
207→        const to_pipe_bytes: u64 = @intCast(to_pipe);
208→        var pipe_iterations: u64 = 0;
209→        const max_pipe_iterations: u64 = to_pipe_bytes +| 1024;
210→        var pipe_retry_count: u32 = 0;
211→        var pipe_last_progress_ns: u64 = last_progress_ns;
212→
213→        // Check if this is the last chunk - don't set SPLICE_F_MORE on final write
214→        // to avoid TCP cork delay. SPLICE_F_MORE tells kernel to expect more data,
215→        // which can cause ~200ms delay waiting for the cork timeout.
216→        const is_last_chunk = (forwarded_bytes + to_pipe_bytes >= length_bytes);
217→        const splice_flags: u32 = if (is_last_chunk)
218→            SPLICE_F_MOVE | SPLICE_F_NONBLOCK
219→        else
220→            SPLICE_F_MOVE | SPLICE_F_MORE | SPLICE_F_NONBLOCK;
221→
222→        while (pipe_sent_bytes < to_pipe_bytes and pipe_iterations < max_pipe_iterations) : (pipe_iterations += 1) {
223→            const from_pipe = spliceSyscall(pipe_fds[0], client_fd, @intCast(to_pipe_bytes - pipe_sent_bytes), splice_flags);
224→            if (from_pipe == 0) return ForwardError.SendFailed;
225→            if (from_pipe < 0) {
226→                if (isLinuxErrno(from_pipe, .INTR)) continue;
227→                if (isLinuxErrno(from_pipe, .AGAIN)) {
228→                    pipe_retry_count += 1;
229→                    const now_ns = serval_time.monotonicNanos();
230→                    if (pipe_retry_count >= SPLICE_MAX_RETRY_COUNT or
231→                        now_ns -| pipe_last_progress_ns >= SPLICE_STALL_TIMEOUT_NS)
232→                    {
233→                        return ForwardError.SpliceFailed;
234→                    }
235→                    _ = waitForSpliceReady(pipe_fds[0], client_fd, posix.POLL.IN, posix.POLL.OUT, SPLICE_POLL_TIMEOUT_MS);
236→                    continue;
237→                }
238→                return ForwardError.SpliceFailed;
239→            }
240→
241→            pipe_retry_count = 0;
242→            pipe_last_progress_ns = serval_time.monotonicNanos();
243→            pipe_sent_bytes += @intCast(from_pipe);
244→        }
245→
246→        if (pipe_sent_bytes != to_pipe_bytes) return ForwardError.SendFailed;
247→        forwarded_bytes += to_pipe_bytes;
248→    }
249→
250→    if (forwarded_bytes < length_bytes and iterations >= max_iterations) {
251→        return ForwardError.SpliceFailed;
252→    }
253→
254→    assert(forwarded_bytes <= length_bytes);
255→    return forwarded_bytes;
256→}
257→
258→fn waitForSpliceReady(
259→    read_fd: i32,
260→    write_fd: i32,
261→    read_events: i16,
262→    write_events: i16,
263→    timeout_ms: i32,
264→) bool {
265→    assert(read_fd >= 0);
266→    assert(write_fd >= 0);
267→    assert(timeout_ms >= 0);
268→
269→    var poll_fds = [_]posix.pollfd{
270→        .{ .fd = read_fd, .events = read_events, .revents = 0 },
271→        .{ .fd = write_fd, .events = write_events, .revents = 0 },
272→    };
273→
274→    const polled = posix.poll(&poll_fds, timeout_ms) catch return false;
275→    if (polled == 0) return false;
276→    if ((poll_fds[0].revents & (posix.POLL.ERR | posix.POLL.NVAL)) != 0) return false;
277→    if ((poll_fds[1].revents & (posix.POLL.ERR | posix.POLL.NVAL)) != 0) return false;
278→    return true;
279→}
