281→fn getFdFlags(fd: i32) !usize {
282→    assert(fd >= 0);
283→
284→    const flags = posix.system.fcntl(fd, posix.F.GETFL, @as(usize, 0));
285→    if (flags < 0) return error.Unexpected;
286→    return @intCast(flags);
287→}
288→
289→fn setFdFlags(fd: i32, flags: usize) !void {
290→    assert(fd >= 0);
291→
292→    const result = posix.system.fcntl(fd, posix.F.SETFL, flags);
293→    if (result < 0) return error.Unexpected;
294→}
295→
296→fn setFdNonBlocking(fd: i32, flags: *usize) !void {
297→    assert(fd >= 0);
298→    assert(@intFromPtr(flags) != 0);
299→
300→    const nonblock_flag = @as(usize, 1) << @bitOffsetOf(posix.O, "NONBLOCK");
301→    if ((flags.* & nonblock_flag) != 0) return;
302→    flags.* |= nonblock_flag;
303→    try setFdFlags(fd, flags.*);
304→}
