307→// Socket-Based Buffered Copy
308→// =============================================================================
309→
310→/// Forward body using Socket read/write (handles both TLS and plaintext).
311→/// TigerStyle: Bounded loops, fixed buffer size, Y3 _bytes suffix.
312→fn forwardBodyCopy(upstream: *Socket, client: *Socket, length_bytes: u64) ForwardError!u64 {
313→    // Precondition: sockets have valid fds.
314→    assert(upstream.get_fd() >= 0);
315→    assert(client.get_fd() >= 0);
316→
317→    var buffer: [COPY_CHUNK_SIZE_BYTES]u8 = std.mem.zeroes([COPY_CHUNK_SIZE_BYTES]u8);
318→    var forwarded_bytes: u64 = 0;
319→    // TigerStyle: explicit worst-case bound (1 byte forward progress per iteration).
320→    const max_iterations: u64 = length_bytes +| 1024;
321→    var iterations: u64 = 0;
322→
323→    while (forwarded_bytes < length_bytes and iterations < max_iterations) : (iterations += 1) {
324→        const remaining_bytes = length_bytes - forwarded_bytes;
325→        const to_read: usize = @intCast(@min(remaining_bytes, buffer.len));
326→
327→        // Read from upstream via Socket abstraction (TLS or plaintext).
328→        const n = upstream.read(buffer[0..to_read]) catch {
329→            return ForwardError.RecvFailed;
330→        };
331→        if (n == 0) break; // Clean shutdown or EOF.
332→
333→        // Write all read bytes to client via Socket abstraction.
334→        client.write_all(buffer[0..n]) catch {
335→            return ForwardError.SendFailed;
336→        };
337→
338→        forwarded_bytes += n;
339→    }
340→
341→    assert(forwarded_bytes <= length_bytes);
342→    return forwarded_bytes;
343→}
