345→// =============================================================================
346→// Request Body Streaming
347→// =============================================================================
348→
349→/// Stream request body from client to upstream.
350→/// Supports Content-Length bodies (known size) and chunked transfer encoding.
351→/// Sends already-read bytes first, then streams remaining from client.
352→/// TigerStyle: Uses Socket for unified TLS/plaintext handling.
353→pub fn streamRequestBody(
354→    client: *Socket,
355→    upstream: *Socket,
356→    upstream_conn: *Connection,
357→    io: Io,
358→    body_info: BodyInfo,
359→) ForwardError!u64 {
360→    // Precondition: valid socket file descriptors.
361→    assert(client.get_fd() >= 0);
362→    assert(upstream.get_fd() >= 0);
363→
364→    // Dispatch based on body framing mode.
365→    const result = switch (body_info.framing) {
366→        .none => 0, // No body to stream (GET, HEAD, etc.)
367→        .content_length => |length| try streamContentLengthBody(
368→            client,
369→            upstream,
370→            upstream_conn,
371→            io,
372→            length,
373→            body_info.bytes_already_read,
374→            body_info.initial_body,
375→        ),
376→        .chunked => try streamChunkedRequestBody(
377→            client,
378→            upstream,
379→            upstream_conn,
380→            io,
381→            body_info.initial_body,
382→        ),
383→    };
384→
385→    // Postcondition: returned bytes is non-negative (always true for u64).
386→    // For content_length, result <= length; for chunked, result >= 5 (min "0\r\n\r\n").
387→    return result;
388→}
389→
390→/// Stream Content-Length body from client to upstream.
391→/// Sends initial_body first, then transfers remaining bytes via Socket.
392→/// TigerStyle: Explicit length, bounded transfer.
393→fn streamContentLengthBody(
394→    client: *Socket,
395→    upstream: *Socket,
396→    upstream_conn: *Connection,
397→    io: Io,
398→    content_length: u64,
399→    bytes_already_read: u64,
400→    initial_body: []const u8,
401→) ForwardError!u64 {
402→    // Preconditions: valid sockets, bytes_already_read cannot exceed content_length.
403→    assert(client.get_fd() >= 0);
404→    assert(upstream.get_fd() >= 0);
405→    assert(bytes_already_read <= content_length);
406→    assert(initial_body.len == @as(usize, @intCast(bytes_already_read)));
407→
408→    var total_sent: u64 = 0;
409→
410→    // Send already-read body bytes via connection (TLS or plaintext).
411→    if (initial_body.len > 0) {
412→        try sendBuffer(upstream_conn, io, initial_body);
413→        total_sent += initial_body.len;
414→    }
415→
416→    // Stream remaining bytes in a fiber-friendly way for concurrent
417→    // request/response forwarding. Plain sockets use io.vtable netRead/netWrite
418→    // to avoid blocking the I/O worker.
419→    const remaining = content_length - bytes_already_read;
420→    if (remaining > 0) {
421→        const forwarded = try forwardBodyCopyFiber(client, upstream, remaining, io);
422→        if (forwarded != remaining) return ForwardError.RecvFailed;
423→        total_sent += forwarded;
424→    }
425→
426→    // Postcondition: content-length bodies must be forwarded exactly.
427→    assert(total_sent == content_length);
428→    return total_sent;
429→}
430→
431→fn forwardBodyCopyFiber(
432→    source: *Socket,
433→    dest: *Socket,
434→    length_bytes: u64,
435→    io: Io,
436→) ForwardError!u64 {
437→    assert(source.get_fd() >= 0);
438→    assert(dest.get_fd() >= 0);
439→
440→    const source_plain = switch (source.*) {
441→        .plain => true,
442→        .tls => false,
443→    };
444→    const dest_plain = switch (dest.*) {
445→        .plain => true,
446→        .tls => false,
447→    };
448→    if (!source_plain or !dest_plain) {
449→        return forwardBodyCopy(source, dest, length_bytes);
450→    }
451→
452→    const source_fd = source.get_fd();
453→    const dest_fd = dest.get_fd();
454→
455→    var buffer: [COPY_CHUNK_SIZE_BYTES]u8 = std.mem.zeroes([COPY_CHUNK_SIZE_BYTES]u8);
456→    var forwarded_bytes: u64 = 0;
457→    const max_iterations: u64 = length_bytes +| 1024;
458→    var iterations: u64 = 0;
459→
460→    while (forwarded_bytes < length_bytes and iterations < max_iterations) : (iterations += 1) {
461→        const remaining_bytes = length_bytes - forwarded_bytes;
462→        const to_read: usize = @intCast(@min(remaining_bytes, buffer.len));
463→
464→        var read_bufs: [1][]u8 = .{buffer[0..to_read]};
465→        const n = io.vtable.netRead(io.userdata, source_fd, &read_bufs) catch return ForwardError.RecvFailed;
466→        if (n == 0) break;
467→
468→        var sent: usize = 0;
469→        while (sent < n) {
470→            const pending = buffer[sent..n];
471→            const write_slices = [_][]const u8{pending};
472→            const written = io.vtable.netWrite(io.userdata, dest_fd, &.{}, &write_slices, 1) catch return ForwardError.SendFailed;
473→            if (written == 0) return ForwardError.SendFailed;
474→            sent += written;
475→        }
476→
477→        forwarded_bytes += n;
478→    }
479→
480→    if (forwarded_bytes < length_bytes and iterations >= max_iterations) {
481→        return ForwardError.RecvFailed;
482→    }
483→
484→    assert(forwarded_bytes <= length_bytes);
485→    return forwarded_bytes;
486→}
487→
488→/// Stream chunked request body from client to upstream.
489→/// Sends initial_body first (may contain partial chunk data), then streams
490→/// remaining chunks using forwardChunkedBody.
491→///
492→/// Design note: For chunked bodies, initial_body may contain partial chunk framing
493→/// read during header parsing. We send this first via the async stream, then
494→/// continue streaming the rest of the chunked body from the client socket.
495→///
496→/// TigerStyle: Bounded chunk iteration (in forwardChunkedBody), explicit error handling.
497→fn streamChunkedRequestBody(
498→    client: *Socket,
499→    upstream: *Socket,
500→    upstream_conn: *Connection,
501→    io: Io,
502→    initial_body: []const u8,
503→) ForwardError!u64 {
504→    // Precondition: valid socket file descriptors.
505→    assert(client.get_fd() >= 0);
506→    assert(upstream.get_fd() >= 0);
507→
508→    var total_sent: u64 = 0;
509→
510→    // Send already-read chunk data via connection (TLS or plaintext).
511→    // This may contain partial chunk headers/data read during request parsing.
512→    if (initial_body.len > 0) {
513→        try sendBuffer(upstream_conn, io, initial_body);
514→        total_sent += initial_body.len;
515→    }
516→
517→    // Stream remaining chunks from client to upstream using Socket abstraction.
518→    // Direction: client (source) -> upstream (destination).
519→    total_sent += try forwardChunkedBodyIo(client, upstream, io);
520→
521→    // Postcondition: total_sent includes initial_body plus chunked stream bytes.
522→    // Minimum chunked body is "0\r\n\r\n" (5 bytes) if no initial_body.
523→    assert(total_sent >= initial_body.len);
524→    return total_sent;
525→}
