531→test "iteration limit supports files >4GB" {
532→    // Verify the iteration calculation works for large files.
533→    // Old limit: 1M iterations × 4KB = 4GB max (would fail for larger files).
534→    // New limit: derived from content length, supports any file size.
535→
536→    // Test cases: various file sizes including >4GB
537→    const test_sizes = [_]u64{
538→        100 * 1024 * 1024, // 100MB
539→        1024 * 1024 * 1024, // 1GB
540→        4 * 1024 * 1024 * 1024, // 4GB (old limit)
541→        5 * 1024 * 1024 * 1024, // 5GB (would fail with old limit)
542→        100 * 1024 * 1024 * 1024, // 100GB
543→        1024 * 1024 * 1024 * 1024, // 1TB
544→    };
545→
546→    for (test_sizes) |length_bytes| {
547→        // Splice path: iterations = length / SPLICE_CHUNK_SIZE + margin
548→        const splice_iterations: u64 = (length_bytes / SPLICE_CHUNK_SIZE_BYTES) + 1024;
549→        const splice_chunks_needed: u64 = (length_bytes / SPLICE_CHUNK_SIZE_BYTES) + 1;
550→
551→        // Copy path: iterations = length / COPY_CHUNK_SIZE + margin
552→        const copy_iterations: u64 = (length_bytes / COPY_CHUNK_SIZE_BYTES) + 1024;
553→        const copy_chunks_needed: u64 = (length_bytes / COPY_CHUNK_SIZE_BYTES) + 1;
554→
555→        // Verify we have enough iterations for the file size
556→        try std.testing.expect(splice_iterations >= splice_chunks_needed);
557→        try std.testing.expect(copy_iterations >= copy_chunks_needed);
558→
559→        // Verify old limit would have failed for >4GB with copy path
560→        const old_limit: u64 = 1024 * 1024;
561→        if (length_bytes > 4 * 1024 * 1024 * 1024) {
562→            try std.testing.expect(copy_chunks_needed > old_limit);
