282→                    }
283→
284→                    const result = self.forwardWebSocketWithConnection(
285→                        io,
286→                        client_stream,
287→                        client_tls,
288→                        request,
289→                        upstream,
290→                        pooled_conn,
291→                        true,
292→                        initial_client_bytes,
293→                        expected_accept,
294→                        0,
295→                        0,
296→                        getLocalPortFromSocket(pooled_conn.socket),
297→                        pool_wait_ns,
298→                        forward_span,
299→                        effective_path,
300→                        forwarded,
