304→                        }
305→                        self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
306→                        self.tracer.setIntAttribute(pool_span, "hit", 0);
307→                        self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
