313→                    self.tracer.setIntAttribute(pool_span, "hit", 1);
314→                    self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
315→                    self.tracer.endSpan(pool_span, null);
316→                    self.tracer.endSpan(forward_span, null);
