320→            }
321→
322→            const pool_wait_ns = time.elapsedNanos(pool_start_ns, time.monotonicNanos());
323→            self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
324→            self.tracer.setIntAttribute(pool_span, "hit", 0);
325→            self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
