 92→/// Maximum attempts when taking TLS reload-control mutex.
 93→/// TigerStyle: Bounded spin loop for control-plane activation path.
 94→const TLS_RELOAD_CONTROL_LOCK_MAX_ATTEMPTS: u32 = 1_000_000;
 95→
 96→fn lockTlsReloadControlMutex(mutex: *std.atomic.Mutex) void {
 97→    assert(@intFromPtr(mutex) != 0);
 98→
 99→    var attempts: u32 = 0;
100→    while (attempts < TLS_RELOAD_CONTROL_LOCK_MAX_ATTEMPTS) : (attempts += 1) {
101→        if (mutex.tryLock()) return;
102→        std.atomic.spinLoopHint();
103→    }
104→
105→    @panic("Server TLS reload control mutex lock timeout");
106→}
