115→fn write_client_addr_ipv4(client_addr: *[46]u8, addr_be: *const [4]u8) EndpointResolveError!void {
116→    assert(@intFromPtr(client_addr) != 0);
117→    assert(@intFromPtr(addr_be) != 0);
118→
119→    @memset(client_addr, 0);
120→    const rendered = std.fmt.bufPrint(
121→        client_addr[0 .. client_addr.len - 1],
122→        "{d}.{d}.{d}.{d}",
123→        .{ addr_be[0], addr_be[1], addr_be[2], addr_be[3] },
124→    ) catch return error.AddressRenderTooLong;
125→    client_addr[rendered.len] = 0;
126→}
