128→fn write_client_addr_ipv6(client_addr: *[46]u8, addr_be: *const [16]u8) EndpointResolveError!void {
129→    assert(@intFromPtr(client_addr) != 0);
130→    assert(@intFromPtr(addr_be) != 0);
131→
132→    const g0: u16 = (@as(u16, addr_be[0]) << 8) | @as(u16, addr_be[1]);
133→    const g1: u16 = (@as(u16, addr_be[2]) << 8) | @as(u16, addr_be[3]);
134→    const g2: u16 = (@as(u16, addr_be[4]) << 8) | @as(u16, addr_be[5]);
135→    const g3: u16 = (@as(u16, addr_be[6]) << 8) | @as(u16, addr_be[7]);
136→    const g4: u16 = (@as(u16, addr_be[8]) << 8) | @as(u16, addr_be[9]);
137→    const g5: u16 = (@as(u16, addr_be[10]) << 8) | @as(u16, addr_be[11]);
138→    const g6: u16 = (@as(u16, addr_be[12]) << 8) | @as(u16, addr_be[13]);
139→    const g7: u16 = (@as(u16, addr_be[14]) << 8) | @as(u16, addr_be[15]);
140→
141→    @memset(client_addr, 0);
142→    const rendered = std.fmt.bufPrint(
143→        client_addr[0 .. client_addr.len - 1],
144→        "{x}:{x}:{x}:{x}:{x}:{x}:{x}:{x}",
145→        .{ g0, g1, g2, g3, g4, g5, g6, g7 },
146→    ) catch return error.AddressRenderTooLong;
147→    client_addr[rendered.len] = 0;
148→}
