699→        pub fn forwardGrpcH2cUpgrade(
700→            self: *Self,
701→            io: Io,
702→            client_stream: Io.net.Stream,
703→            client_tls: ?*TLSStream,
704→            request: *const Request,
705→            upstream: *const Upstream,
706→            body_info: BodyInfo,
