713→            assert(decoded_settings_payload.len <= config.H2_MAX_FRAME_SIZE_BYTES);
714→
715→            if (client_tls != null) return ForwardError.UnsupportedProtocol;
716→            if (upstream.http_protocol != .h2c) return ForwardError.UnsupportedProtocol;
717→            if (upstream.tls) return ForwardError.UnsupportedProtocol;
718→            if (body_info.framing == .chunked) return ForwardError.UnsupportedProtocol;
719→
720→            const request_class = serval_grpc.classifyRequest(request);
721→            if (request_class != .grpc) return ForwardError.UnsupportedProtocol;
722→
723→            const forward_span = self.tracer.startSpan("forward_grpc_h2c_upgrade", parent_span);
724→            errdefer self.tracer.endSpan(forward_span, "forward_error");
725→
726→            const connect_span = self.tracer.startSpan("connect_upstream", forward_span);
727→            const connect_cfg = ConnectConfig{
728→                .timeout_ns = config.CONNECT_TIMEOUT_NS,
729→                .verify_upstream_tls = self.verify_upstream_tls,
730→                .client_ctx = self.client_ctx,
731→            };
732→            const connect_result = connectUpstream(
733→                upstream,
734→                io,
735→                connect_cfg,
736→                &self.dns_resolver,
737→            ) catch |err| {
738→                self.tracer.endSpan(connect_span, @errorName(err));
739→                return err;
740→            };
741→            self.tracer.setIntAttribute(connect_span, "dns_duration_ns", @intCast(connect_result.dns_duration_ns));
742→            self.tracer.setIntAttribute(connect_span, "tcp_connect_duration_ns", @intCast(connect_result.tcp_connect_duration_ns));
