744→
745→            var upstream_socket = connect_result.socket;
746→            defer upstream_socket.close();
747→            var client_socket = Socket.Plain.init_client(client_stream.socket.handle);
748→
749→            const content_length = body_info.getContentLength() orelse 0;
750→            assert(body_info.bytes_already_read <= content_length);
751→            const remaining_body_bytes = content_length - body_info.bytes_already_read;
752→            const has_request_body = content_length > 0;
