777→                &client_socket,
778→                &upstream_socket,
779→                remaining_body_bytes,
780→                initial_client_bytes_after_body,
781→            );
782→            self.tracer.setIntAttribute(tunnel_span, "duration_ns", @intCast(tunnel_stats.duration_ns));
783→            self.tracer.setIntAttribute(tunnel_span, "client_to_upstream_bytes", @intCast(tunnel_stats.client_to_upstream_bytes));
784→            self.tracer.setIntAttribute(tunnel_span, "upstream_to_client_bytes", @intCast(tunnel_stats.upstream_to_client_bytes));
