808→        fn relayGrpcH2cUpgradeSession(
809→            io: Io,
810→            client_socket: *Socket,
811→            upstream_socket: *Socket,
812→            remaining_body_bytes: u64,
813→            initial_client_bytes_after_body: []const u8,
814→        ) tunnel_mod.TunnelStats {
815→            const start_ns = time.monotonicNanos();
816→            var stats = tunnel_mod.TunnelStats{};
817→
818→            if (remaining_body_bytes > 0) {
819→                if (streamGrpcH2cUpgradeBody(client_socket, upstream_socket, remaining_body_bytes, &stats.client_to_upstream_bytes)) |termination| {
820→                    stats.duration_ns = @intCast(time.elapsedNanos(start_ns, time.monotonicNanos()));
821→                    stats.termination = termination;
822→                    return stats;
823→                }
824→            }
825→
826→            const tunnel_stats = tunnel_mod.relayWithConfig(
827→                io,
828→                client_socket,
829→                upstream_socket,
830→                initial_client_bytes_after_body,
831→                &[_]u8{},
832→                config.H2C_TUNNEL_IDLE_TIMEOUT_NS,
833→                config.H2C_TUNNEL_POLL_TIMEOUT_MS,
834→            );
835→            stats.client_to_upstream_bytes += tunnel_stats.client_to_upstream_bytes;
836→            stats.upstream_to_client_bytes += tunnel_stats.upstream_to_client_bytes;
837→            stats.duration_ns = @intCast(time.elapsedNanos(start_ns, time.monotonicNanos()));
838→            stats.termination = tunnel_stats.termination;
839→            return stats;
840→        }
