842→        fn streamGrpcH2cUpgradeBody(
843→            client_socket: *Socket,
844→            upstream_socket: *Socket,
845→            remaining_body_bytes: u64,
846→            counter_bytes: *u64,
847→        ) ?tunnel_mod.Termination {
848→            assert(remaining_body_bytes > 0);
849→
850→            var body_buf: [config.H2_MAX_FRAME_SIZE_BYTES]u8 = undefined;
851→            var remaining = remaining_body_bytes;
852→
853→            while (remaining > 0) {
854→                const to_read: usize = @intCast(@min(remaining, config.H2_MAX_FRAME_SIZE_BYTES));
855→                const bytes_read = client_socket.read(body_buf[0..to_read]) catch |err| {
856→                    return mapClientReadTermination(err);
857→                };
858→                if (bytes_read == 0) return .client_closed;
859→
860→                const end_stream = remaining == bytes_read;
861→                sendH2DataFrames(upstream_socket, body_buf[0..bytes_read], end_stream) catch |err| {
862→                    return mapUpstreamWriteTermination(err);
863→                };
864→                counter_bytes.* += bytes_read;
865→                remaining -= bytes_read;
866→            }
867→
868→            return null;
869→        }
