871→        fn sendH2DataFrames(
872→            upstream_socket: *Socket,
873→            payload: []const u8,
874→            end_stream: bool,
875→        ) serval_socket.SocketError!void {
876→            if (payload.len == 0) {
877→                if (end_stream) try sendH2Frame(upstream_socket, .data, serval_h2.flags_end_stream, H2C_UPGRADE_STREAM_ID, &[_]u8{});
878→                return;
879→            }
880→
881→            var cursor: usize = 0;
882→            while (cursor < payload.len) {
883→                const remaining = payload.len - cursor;
884→                const chunk_len: usize = @intCast(@min(remaining, config.H2_MAX_FRAME_SIZE_BYTES));
885→                const chunk = payload[cursor .. cursor + chunk_len];
886→                const is_last_chunk = cursor + chunk_len == payload.len;
887→                const flags: u8 = if (end_stream and is_last_chunk) serval_h2.flags_end_stream else 0;
888→                try sendH2Frame(upstream_socket, .data, flags, H2C_UPGRADE_STREAM_ID, chunk);
889→                cursor += chunk_len;
890→            }
891→        }
