893→        fn sendH2Frame(
894→            upstream_socket: *Socket,
895→            frame_type: serval_h2.FrameType,
896→            flags: u8,
897→            stream_id: u32,
898→            payload: []const u8,
899→        ) serval_socket.SocketError!void {
900→            var header_buf: [serval_h2.frame_header_size_bytes]u8 = undefined;
901→            const header = serval_h2.buildFrameHeader(&header_buf, .{
902→                .length = @intCast(payload.len),
903→                .frame_type = frame_type,
904→                .flags = flags,
905→                .stream_id = stream_id,
906→            }) catch return serval_socket.SocketError.Unexpected;
907→            try upstream_socket.write_all(header);
908→            if (payload.len > 0) try upstream_socket.write_all(payload);
909→        }
