911→        fn mapClientReadTermination(err: serval_socket.SocketError) tunnel_mod.Termination {
912→            return switch (err) {
913→                error.ConnectionClosed => .client_closed,
914→                else => .client_error,
915→            };
916→        }
917→
918→        fn mapUpstreamWriteTermination(err: serval_socket.SocketError) tunnel_mod.Termination {
919→            return switch (err) {
920→                error.ConnectionClosed => .upstream_closed,
921→                else => .upstream_error,
922→            };
923→        }
