925→        /// Forward request using an established upstream connection.
926→        /// effective_path: If set, use this path instead of request.path (for path rewriting).
927→        /// TigerStyle: Explicit io parameter, streams for async I/O.
928→        fn forwardWithConnection(
929→            self: *Self,
930→            io: Io,
931→            client_stream: Io.net.Stream,
932→            client_tls: ?*TLSStream,
933→            request: *const Request,
934→            upstream: *const Upstream,
935→            conn: Connection,
936→            is_pooled: bool,
937→            body_info: BodyInfo,
938→            dns_duration_ns: u64,
939→            tcp_connect_duration_ns: u64,
940→            local_port: u16,
941→            pool_wait_ns: u64,
942→            forward_span: SpanHandle,
943→            effective_path: ?[]const u8,
944→        ) ForwardError!ForwardResult {
945→            var mutable_conn = conn;
946→            errdefer {
947→                // TigerStyle: Maintain accounting integrity on error path
948→                // If connection came from pool, must call release() to decrement checked_out_counts
949→                // Otherwise stats show phantom "checked out" connections forever
950→                if (is_pooled) {
951→                    // Release with healthy=false (don't return to pool, but update counts)
952→                    self.pool.release(upstream.idx, mutable_conn, false);
953→                } else {
954→                    // Fresh connection never entered pool, just close it
955→                    mutable_conn.close();
956→                }
957→            }
958→
959→            // Send phase span (headers + body)
960→            const send_span = self.tracer.startSpan("send_request", forward_span);
961→            const send_start_ns = time.monotonicNanos();
962→            debugLog("send: start headers", .{});
963→
964→            // Send request headers to upstream via connection (TLS or plaintext)
965→            // Pass effective_path for path rewriting support
966→            sendRequest(&mutable_conn, io, request, effective_path) catch |err| {
967→                debugLog("send: FAILED err={s}", .{@errorName(err)});
968→                self.tracer.endSpan(send_span, @errorName(err));
969→                if (is_pooled and err == ForwardError.SendFailed) {
970→                    return ForwardError.StaleConnection;
971→                }
972→                return err;
973→            };
974→
975→            // Create Socket wrappers for body forwarding.
976→            // TigerStyle: Connection.socket is already a Socket, use it directly for upstream.
977→            // For client, create Socket from client_tls or plaintext fd.
978→            var client_socket = if (client_tls) |tls|
979→                Socket{ .tls = .{ .fd = client_stream.socket.handle, .stream = tls.* } }
980→            else
981→                Socket.Plain.init_client(client_stream.socket.handle);
