983→            // Stream request body concurrently with reading the upstream response.
984→            //
985→            // Sequential body-then-response causes a TCP deadlock when the upstream
986→            // echoes or streams back a response while receiving the request body:
987→            //   - proxy blocks writing body (upstream TCP recv buffer full)
988→            //   - upstream blocks sending response (proxy not reading)
989→            // Running both directions concurrently breaks the deadlock.
990→            //
991→            // Context struct for the background body-streaming task.
992→            // All fields are pointers into the current stack frame, so we must
993→            // ensure the task completes before forwardWithConnection returns.
994→            const BodyCtx = struct {
995→                client: *Socket,
996→                upstream: *Socket,
997→                conn: *Connection,
998→                io: Io,
999→                body_info: BodyInfo,

1000→                result: ForwardError!u64 = 0,
1001→
1002→                fn run(bctx: *@This()) Io.Cancelable!void {
1003→                    debugLog("send: body stream task start", .{});
1004→                    bctx.result = streamRequestBody(
1005→                        bctx.client,
1006→                        bctx.upstream,
1007→                        bctx.conn,
1008→                        bctx.io,
1009→                        bctx.body_info,
1010→                    );
1011→                    if (bctx.result) |bytes_sent| {
1012→                        debugLog("send: body stream task complete bytes={d}", .{bytes_sent});
1013→                    } else |err| {
1014→                        debugLog("send: body stream task failed err={s}", .{@errorName(err)});
1015→                    }
1016→                }
1017→            };
1018→
1019→            var body_ctx: BodyCtx = undefined;
1020→            var body_group: Io.Group = .init;
1021→            // LIFO errdefer: runs BEFORE the pool-release errdefer defined above,
1022→            // ensuring the background task releases its references to mutable_conn
1023→            // before the connection is returned to the pool on any error path.
1024→            errdefer body_group.cancel(io);
1025→
1026→            const has_body = if (body_info.getContentLength()) |content_length| blk: {
1027→                if (content_length > config.MAX_BODY_SIZE_BYTES) {
1028→                    self.tracer.endSpan(send_span, "RequestBodyTooLarge");
1029→                    return ForwardError.RequestBodyTooLarge;
1030→                }
1031→                debugLog("send: streaming body concurrently content_length={d}", .{content_length});
1032→                body_ctx = .{
1033→                    .client = &client_socket,
1034→                    .upstream = &mutable_conn.socket,
1035→                    .conn = &mutable_conn,
1036→                    .io = io,
1037→                    .body_info = body_info,
1038→                    .result = 0,
1039→                };
