1042→            } else false;
1043→
1044→            const send_end_ns = time.monotonicNanos();
1045→            const send_duration_ns = time.elapsedNanos(send_start_ns, send_end_ns);
1046→            self.tracer.setIntAttribute(send_span, "duration_ns", @intCast(send_duration_ns));
1047→            self.tracer.endSpan(send_span, null);
1048→            debugLog("send: complete duration_us={d}", .{send_duration_ns / 1000});
1049→
1050→            // Recv phase span (response headers + body).
1051→            // Runs concurrently with body streaming when has_body is true.
1052→            const recv_span = self.tracer.startSpan("recv_response", forward_span);
1053→            debugLog("recv: awaiting response headers", .{});
1054→            var result = forwardResponse(io, &mutable_conn, client_stream, &mutable_conn.socket, &client_socket, is_pooled) catch |err| {
1055→                self.tracer.endSpan(recv_span, @errorName(err));
1056→                return err;
1057→            };
1058→            self.tracer.setIntAttribute(recv_span, "duration_ns", @intCast(result.recv_duration_ns));
1059→            self.tracer.setIntAttribute(recv_span, "status", result.status);
1060→            self.tracer.setIntAttribute(recv_span, "bytes", @intCast(result.response_bytes));
1061→            self.tracer.endSpan(recv_span, null);
1062→
1063→            result.connection_reused = is_pooled;
1064→            result.dns_duration_ns = dns_duration_ns;
1065→            result.tcp_connect_duration_ns = tcp_connect_duration_ns;
1066→            result.send_duration_ns = send_duration_ns;
1067→            result.pool_wait_ns = pool_wait_ns;
1068→            result.upstream_local_port = local_port;
1069→
1070→            // Wait for body streaming to finish before releasing the connection.
1071→            // Must happen before pool.release so the background task no longer
1072→            // holds references to mutable_conn.
1073→            body_group.await(io) catch |err| {
1074→                debugLog("send: body group await failed err={s}", .{@errorName(err)});
1075→            };
1076→            if (has_body) {
1077→                _ = body_ctx.result catch |err| {
1078→                    debugLog("send: body stream error={s}", .{@errorName(err)});
1079→                };
1080→            }
1081→
1082→            // RFC 9112 recommends checking upstream's Connection: close header and not
1083→            // pooling if present. Current implementation relies on StaleConnection retry
1084→            // (Pingora-style). Consider adding explicit header check if retry overhead
1085→            // becomes measurable.
1086→            self.pool.release(upstream.idx, mutable_conn, true);
