  2→//! Connection Pool Interface
  3→//!
  4→//! Comptime interface for connection pooling.
  5→//! Includes SimplePool (fixed-size) and NoPool (no pooling).
  6→//! TigerStyle: No runtime allocation, fixed sizes.
  7→
  8→const std = @import("std");
  9→const assert = std.debug.assert;
 10→
 11→const config = @import("serval-core").config;
 12→const time = @import("serval-core").time;
 13→const UpstreamIndex = config.UpstreamIndex;
 14→
 15→// debug
 16→const serval_core = @import("serval-core");
 17→const log = serval_core.log.scoped(.pool);
 18→const debugLog = serval_core.debugLog;
 19→
