 23→// =============================================================================
 24→// Pool Interface Verification
 25→// =============================================================================
 26→
 27→pub fn verifyPool(comptime Pool: type) void {
 28→    if (!@hasDecl(Pool, "acquire")) {
 29→        @compileError("Pool must implement: pub fn acquire(self, upstream_idx: UpstreamIndex) ?Connection");
 30→    }
 31→    if (!@hasDecl(Pool, "release")) {
 32→        @compileError("Pool must implement: pub fn release(self, upstream_idx: UpstreamIndex, conn: Connection, healthy: bool) void");
 33→    }
 34→    if (!@hasDecl(Pool, "drain")) {
 35→        @compileError("Pool must implement: pub fn drain(self) void");
 36→    }
 37→}
