106→    /// Returns true if connection should NOT be reused.
107→    /// TigerStyle: Positive naming - true means "bad, don't use".
108→    pub fn isUnusable(self: *const Connection) bool {
109→        const fd = self.socket.get_fd();
110→        if (fd < 0) return true;
111→
112→        var poll_fds = [_]std.posix.pollfd{
113→            .{
114→                .fd = fd,
115→                .events = std.posix.POLL.IN,
116→                .revents = 0,
117→            },
118→        };
119→
120→        // Poll with 0 timeout = non-blocking check
121→        const result = std.posix.poll(&poll_fds, 0) catch |err| {
122→            // TigerStyle: Log errors instead of silently swallowing
123→            log.debug("isUnusable poll failed on fd {d}: {s}", .{ fd, @errorName(err) });
124→            return true; // Assume unusable on error
125→        };
126→
127→        if (result > 0) {
128→            if ((poll_fds[0].revents & STALE_CONNECTION_FLAGS) != 0) return true;
129→        }
130→
131→        return false;
132→    }
