553→
554→    const stream = self.state.getStream(header.stream_id) orelse return error.StreamNotFound;
555→    if (!stream.remoteCanSend()) return error.InvalidDataStream;
556→
557→    const data_payload = if ((header.flags & h2.flags_padded) != 0)
558→        try trimPaddedPayload(payload)
