560→        payload;
561→
562→    const payload_len: u32 = @intCast(payload.len);
563→
564→    // RFC 9113 flow-control: classify stream-level exhaustion distinctly and
565→    // avoid mutating connection window on stream-local underflow.
566→    if (payload_len > self.state.flow.recv_window.available_bytes) return error.WindowUnderflow;
567→    if (payload_len > stream.recv_window.available_bytes) return error.StreamFlowControlError;
568→
569→    try self.state.consumeRecvWindow(payload_len);
570→    self.state.consumeStreamRecvWindow(header.stream_id, payload_len) catch |err| switch (err) {
571→        error.WindowUnderflow,
572→        error.WindowOverflow,
573→        error.InvalidIncrement,
574→        => return error.StreamFlowControlError,
575→        else => return err,
