579→    try noteRequestData(self, header.stream_id, data_payload.len, end_stream);
580→    if (end_stream) try self.state.endRemoteStream(header.stream_id);
581→    return .{ .request_data = .{ .stream_id = header.stream_id, .end_stream = end_stream, .payload = data_payload } };
582→}
