) void {
    const response_text = "HTTP/1.1 100 Continue\r\n\r\n";
    assert(std.mem.endsWith(u8, response_text, "\r\n\r\n")); // S2: postcondition
    connectionWrite(maybe_tls, io, stream, response_text) catch return;
}

