    maybe_tls_ptr, &io_mut, stream, metrics, tracer,
    span_handle, &buffer_offset,
)) {
    .close_connection => return,
    .continue_loop => continue,
    .fall_through => {},
}
const upstream = ctx.upstream.?;
```

