    var reader = BodyReader{
        .framing = .{ .content_length = 100 },
        .bytes_already_read = 0,
        .initial_body = &[_]u8{},
        .read_ctx = null,
        .read_fn = null,
        .total_bytes_read = 50,
    };
    try std.testing.expect(!isBodyConsumed(&reader, .{ .content_length = 100 }));
}

test "isBodyConsumed returns true for no-body request" {
    var reader = BodyReader{
        .framing = .none,
        .bytes_already_read = 0,
        .initial_body = &[_]u8{},
